"""Pandera type annotations for GeoPandas."""

import functools
import io
import json
from typing import (  # type: ignore[attr-defined]
    TYPE_CHECKING,
    Any,
    Generic,
    TypeVar,
    Union,
    _type_check,
    get_args,
)

import pandas as pd

from pandera.engines import PYDANTIC_V2
from pandera.errors import SchemaError, SchemaInitError
from pandera.typing.common import DataFrameBase, DataFrameModel, SeriesBase
from pandera.typing.formats import Formats

if PYDANTIC_V2:
    from pydantic import GetCoreSchemaHandler
    from pydantic_core import core_schema

try:
    import geopandas as gpd

    try:
        from typing import _GenericAlias  # type: ignore[attr-defined]
    except ImportError:  # pragma: no cover
        _GenericAlias = None

    GEOPANDAS_INSTALLED = True
except (ImportError, AttributeError):  # pragma: no cover
    # AttributeError can occur when geopandas is installed but incompatible
    # with the current pandas version
    GEOPANDAS_INSTALLED = False


if GEOPANDAS_INSTALLED:
    from pandera.engines.geopandas_engine import Geometry

    if TYPE_CHECKING:
        T = TypeVar("T")  # pragma: no cover
    else:
        T = DataFrameModel

    class GeoSeries(SeriesBase, gpd.GeoSeries, Generic[T]):
        """
        Representation of geopandas.GeoSeries, only used for type annotation.
        """

        default_dtype = Geometry

    class GeoDataFrame(DataFrameBase, gpd.GeoDataFrame, Generic[T]):
        """
        A generic type for geopandas.GeoDataFrame.
        """

        @property
        def _constructor(self):
            """Return the plain gpd.GeoDataFrame constructor.

            Geopandas >= 1.1 uses a classmethod constructor that binds
            to ``type(self)``. For pandera's GeoDataFrame subclass this
            causes ``__class__`` assignment failures due to incompatible
            C-level memory layouts. Binding to ``gpd.GeoDataFrame``
            ensures derived objects are plain GeoDataFrames.
            """
            return gpd.GeoDataFrame._geodataframe_constructor_with_fallback

        def copy(self, deep: bool = True) -> gpd.GeoDataFrame:
            """Copy that avoids ``__class__`` reassignment to this subclass.

            Geopandas >= 1.1 reassigns ``__class__`` to ``type(self)``
            inside ``copy()``.  That fails for this pandera subclass
            because its C-level layout is incompatible with
            ``pd.DataFrame``.  We replicate the geopandas logic but
            target ``gpd.GeoDataFrame`` instead.
            """
            copied = pd.DataFrame.copy(self, deep=deep)
            if type(copied) is pd.DataFrame:
                copied.__class__ = gpd.GeoDataFrame
                copied._geometry_column_name = self._geometry_column_name
            return copied

        if hasattr(gpd.GeoDataFrame, "__class_getitem__") and _GenericAlias:

            def __class_getitem__(cls, item):
                """Define this to override the patch that pyspark.pandas performs on pandas.
                https://github.com/apache/spark/blob/master/python/pyspark/pandas/__init__.py#L124-L144
                """
                _type_check(item, "Parameters to generic types must be types.")
                return _GenericAlias(cls, item)

        @classmethod
        def _coerce_geometry(
            cls, obj: Union[pd.DataFrame, gpd.GeoDataFrame]
        ) -> gpd.GeoDataFrame:
            if not isinstance(obj, gpd.GeoDataFrame):
                # Construct GeoDataFrame if given a vanilla DataFrame.
                # We have confidence in geometry column being a Geometry dtype,
                # so try to coerce and assign as active geometry. Not so much
                # confidence in other columns because we don't have access to
                # the schema model here.
                if "geometry" in obj.columns:
                    # Coerce data into GeoPandas-acceptible format
                    obj["geometry"] = Geometry()._coerce_values(
                        obj["geometry"]
                    )

                    # Construct with active geometry
                    obj = gpd.GeoDataFrame(obj, geometry="geometry")
                else:
                    # Construct without active geometry
                    obj = gpd.GeoDataFrame(obj)
            return obj

        @classmethod
        def from_format(cls, obj: Any, config) -> gpd.GeoDataFrame:
            """
            Converts serialized data from a specific format
            specified in the :py:class:`pandera.api.pandas.model.DataFrameModel` config options
            ``from_format`` and ``from_format_kwargs``.

            :param obj: object representing a serialized dataframe.
            :param config: dataframe model configuration object.
            """
            if config.from_format is None:
                if not isinstance(obj, gpd.GeoDataFrame):
                    try:
                        # Start with loading in Pandas because DataFrame
                        # is more flexible, as opposed to the crotchety
                        # old man of GeoDataFrame who excepcts its geometry
                        # column to be ready-made for GeoSeries.
                        obj = pd.DataFrame(obj)

                        # Coerce into GeoDataFrame, which attempts to
                        # convert the geometry column even if in a
                        # non-standard format (geojson dict, wkt, etc.)
                        obj = cls._coerce_geometry(obj)
                    except Exception as exc:
                        raise ValueError(
                            f"Expected gpd.GeoDataFrame, found {type(obj)}"
                        ) from exc
                return obj

            if callable(config.from_format):
                reader = config.from_format
            else:
                reader = {
                    Formats.dict: gpd.GeoDataFrame,
                    Formats.csv: pd.read_csv,
                    Formats.json: lambda x: gpd.GeoDataFrame.from_features(
                        json.loads(x)
                    ),
                    Formats.feather: pd.read_feather,
                    Formats.parquet: pd.read_parquet,
                    Formats.pickle: pd.read_pickle,
                }[Formats(config.from_format)]
            parsed = reader(obj, **(config.from_format_kwargs or {}))  # type: ignore
            return cls._coerce_geometry(parsed)

        @classmethod
        def to_format(cls, data: gpd.GeoDataFrame, config) -> Any:
            """
            Converts a geodataframe to the format specified in the
            :py:class:`pandera.api.pandas.model.DataFrameModel` config options ``to_format``
            and ``to_format_kwargs``.

            :param data: convert this data to the specified format
            :param config: :py:cl
            """
            if config.to_format is None:
                return data

            if callable(config.to_format):
                writer = functools.partial(config.to_format, data)
                if callable(config.to_format_buffer):
                    buffer = config.to_format_buffer()
                elif config.to_format_buffer is None:
                    buffer = None
                else:  # pragma: no cover
                    raise TypeError(
                        "to_format_buffer must be Callable or None, found "
                        f"{config.to_format_buffer}"
                    )
            else:
                writer, buffer = {  # type: ignore[assignment]
                    Formats.dict: (data.to_dict, None),
                    Formats.csv: (data.to_csv, None),
                    Formats.json: (data.to_json, None),
                    Formats.feather: (data.to_feather, io.BytesIO()),
                    Formats.parquet: (data.to_parquet, io.BytesIO()),
                    Formats.pickle: (data.to_pickle, io.BytesIO()),
                }[Formats(config.to_format)]

            args = [] if buffer is None else [buffer]
            out = writer(*args, **(config.to_format_kwargs or {}))  # type: ignore
            if buffer is None:
                return out
            elif buffer.closed:
                raise OSError(
                    f"geopandas=={gpd.__version__} closed the buffer automatically "
                    f"using the serialization method {writer}. Use a later "
                    "version of pandas or use a different the serialization "
                    "format."
                )
            buffer.seek(0)
            return buffer

        @classmethod
        def _get_schema_model(cls, field):
            if not field.sub_fields:
                raise TypeError(
                    "Expected a typed pandera.typing.GeoDataFrame,"
                    " e.g. GeoDataFrame[Schema]"
                )
            schema_model = field.sub_fields[0].type_
            return schema_model

        if PYDANTIC_V2:

            @classmethod
            def __get_pydantic_core_schema__(
                cls, _source_type: Any, _handler: GetCoreSchemaHandler
            ) -> core_schema.CoreSchema:
                schema_model = get_args(_source_type)[0]
                return core_schema.no_info_plain_validator_function(
                    functools.partial(
                        cls.pydantic_validate,
                        schema_model=schema_model,
                    ),
                )

        else:

            @classmethod
            def __get_validators__(cls):
                yield cls._pydantic_validate

        @classmethod
        def pydantic_validate(cls, obj: Any, schema_model) -> gpd.GeoDataFrame:
            """
            Verify that the input can be converted into a pandas dataframe that
            meets all schema requirements.

            This is for pydantic >= v2
            """
            try:
                schema = schema_model.to_schema()
            except SchemaInitError as exc:
                raise ValueError(
                    f"Cannot use {cls.__name__} as a pydantic type as its "
                    "DataFrameModel cannot be converted to a DataFrameSchema.\n"
                    f"Please revisit the model to address the following errors:"
                    f"\n{exc}"
                ) from exc

            data = cls.from_format(obj, schema_model.__config__)

            try:
                valid_data = schema.validate(data)
            except SchemaError as exc:
                raise ValueError(str(exc)) from exc

            return cls.to_format(valid_data, schema_model.__config__)

        @classmethod
        def _pydantic_validate(cls, obj: Any, field) -> gpd.GeoDataFrame:
            """
            Verify that the input can be converted into a geopandas geodataframe that
            meets all schema requirements.

            This is for pydantic < v1
            """
            schema_model = cls._get_schema_model(field)
            return cls.pydantic_validate(obj, schema_model)

"""Geopandas data types for the pandas type engine."""

from collections.abc import Iterable
from typing import Any, Optional, Union

try:
    import geopandas as gpd

    GEOPANDAS_INSTALLED = True
except ImportError:
    GEOPANDAS_INSTALLED = False


import dataclasses

import numpy as np
import pandas as pd
import pyproj
import shapely
import shapely.geometry
from geopandas.array import GeometryArray, GeometryDtype, from_shapely

from pandera import dtypes, errors
from pandera.engines import pandas_engine

GeoPandasObject = Union[
    pd.Series, pd.DataFrame, gpd.GeoSeries, gpd.GeoDataFrame
]


@pandas_engine.Engine.register_dtype(
    equivalents=[
        "geometry",
        GeometryDtype,
        GeometryDtype(),
    ],
)
@dtypes.immutable(init=True)
class Geometry(pandas_engine.DataType):
    """Semantic representation of geopandas :class:`geopandas.array.GeometryDtype`.

    Extends the native GeometryDtype by allowing designation of a coordinate
    reference system (CRS) as found on GeometryArray, GeoSeries, and GeoDataFrame.
    When the CRS is defined, validator will check for matching CRS, and coerce
    will transform coordinate values via GeoPandas' 'to_crs' method. Otherwise, CRS
    of data is ignored.
    """

    type = GeometryDtype()

    crs: str | None = dataclasses.field(default=None)
    """Coordinate Reference System of the geometry objects.
    """

    # define __init__ to please mypy
    def __init__(
        self,
        crs: Any | None = None,
    ) -> None:
        if crs is not None:
            try:
                pyproj.CRS.from_user_input(crs)
            except pyproj.exceptions.CRSError as exc:
                raise TypeError(f"Invalid CRS: {str(crs)}") from exc

            object.__setattr__(self, "crs", crs)

    def _coerce_values(self, obj: GeoPandasObject) -> GeoPandasObject:
        if isinstance(obj, gpd.GeoSeries) or (
            isinstance(obj, (pd.DataFrame, gpd.GeoDataFrame))
            and all(v == str(self) for v in obj.dtypes.to_dict().values())
        ):
            # Return as-is if we already have the proper underlying dtype
            return obj

        # Shapely objects
        try:
            return from_shapely(obj)
        except TypeError:
            ...

        # Well-known Text (WKT) strings
        try:
            return from_shapely(shapely.from_wkt(obj))
        except (TypeError, shapely.errors.GEOSException):
            ...

        # Well-known Binary (WKB) strings
        try:
            return from_shapely(shapely.from_wkb(obj))
        except (TypeError, shapely.errors.GEOSException):
            ...

        # JSON/GEOJSON dictionary
        return from_shapely(obj.map(self._coerce_element))  # type: ignore[operator]

    def _coerce_element(self, element: Any) -> Any:
        try:
            return shapely.geometry.shape(element)
        except (
            AttributeError,
            TypeError,
            shapely.errors.GeometryTypeError,
            shapely.errors.GEOSException,
        ):
            return np.nan

    def _coerce_crs(self, value: GeoPandasObject) -> GeoPandasObject:
        if self.crs is not None:
            if value.crs is None:
                # Allow assignment of CRS if currently
                # null and a non-null value is designated.
                # This will only work in the context of
                # geopandas because assigning geometry
                # CRS to a pandas dataframe isn't supported.
                value.crs = self.crs
            elif isinstance(value, gpd.GeoSeries) and self.crs != value.crs:
                value = value.to_crs(self.crs)  # type: ignore[operator]
            elif isinstance(value, gpd.GeoDataFrame) and any(
                self.crs != value[col].crs for col in value.columns
            ):
                for col in value.columns:
                    if self.crs != value[col].crs:
                        value[col] = value[col].to_crs(self.crs)
        return value

    def coerce(self, data_container: GeoPandasObject) -> GeoPandasObject:
        """Coerce data container to the specified data type."""

        from pandera.backends.pandas import error_formatters

        orig_isna = data_container.isna()

        # Copy so we don't directly modify container due
        # to CRS re-projection, etc.)
        data_container = data_container.copy()

        # Coerce container data
        coerced_data = self._coerce_values(data_container)

        # Coerce container type
        if isinstance(coerced_data, (GeometryArray, pd.DataFrame)):
            if isinstance(data_container, (pd.Series, gpd.GeoSeries)):
                coerced_data = gpd.GeoSeries(coerced_data)
            else:
                coerced_data = gpd.GeoDataFrame(coerced_data)

        failed_selector = coerced_data.isna() & ~orig_isna

        if np.any(failed_selector.any()):
            failure_cases = coerced_data[failed_selector]
            raise errors.ParserError(
                f"Could not coerce {type(data_container)} data_container "
                f"into type {self.type}",
                failure_cases=error_formatters.reshape_failure_cases(
                    failure_cases, ignore_na=False
                ),
            )
        coerced = self._coerce_crs(coerced_data)
        return coerced

    def check(  # type: ignore
        self,
        pandera_dtype: pandas_engine.DataType,
        data_container: GeoPandasObject | None = None,
    ) -> Union[bool, Iterable[bool]]:
        """Check data container to the specified data type."""
        # Type check
        if not super().check(pandera_dtype, data_container):
            if data_container is None:
                return False
            else:
                return np.full_like(data_container, False, dtype=bool)
        if self.crs != pandera_dtype.crs and data_container is None:  # type: ignore[attr-defined]
            return False

        # CRS check extends into container
        if self.crs is not None:
            if (
                isinstance(data_container, gpd.GeoSeries)
                and data_container.crs != self.crs
            ):
                # GeoSeries
                raise TypeError(
                    f"CRS mismatch; actual {str(data_container.crs)}, expected {str(self.crs)}"
                )
            if isinstance(data_container, gpd.GeoDataFrame):
                # GeoDataFrame
                col_results = []
                for col in data_container.columns:
                    if data_container[col].crs != self.crs:
                        col_err = f"CRS mismatch on column {col}; actual {str(data_container[col].crs)}, expected {str(self.crs)}"
                        col_results.append(col_err)
                if col_results:
                    raise TypeError("\n".join(col_results))

        return np.full_like(data_container, True, dtype=bool)

    def __eq__(self, obj: object) -> bool:
        if isinstance(obj, type(self)):
            return obj.crs == self.crs
        return super().__eq__(obj)

    def __str__(self) -> str:
        return "geometry"

