from typing import Union, overload

import geopandas as gpd
import pandas as pd

from pandera.api.geopandas.container import GeoDataFrameSchema
from pandera.api.pandas.array import SeriesSchema
from pandera.engines.geopandas_engine import Geometry
from pandera.schema_inference.pandas import (
    infer_dataframe_schema,
    infer_series_schema,
)


@overload
def infer_schema(
    geopandas_obj: gpd.GeoSeries,
) -> SeriesSchema:  # pragma: no cover
    ...


@overload
def infer_schema(  # type: ignore[misc]
    geopandas_obj: Union[pd.DataFrame, gpd.GeoDataFrame],
) -> GeoDataFrameSchema:  # pragma: no cover
    ...


def infer_schema(geopandas_obj):
    """Infer schema for a geopandas GeoDataFrame or GeoSeries object.

    :param geopandas_obj: GeoDataFrame or GeoSeries object to infer.
    :returns: GeoDataFrameSchema or SeriesSchema
    :raises: TypeError if geopandas_obj is not expected type.
    """
    if isinstance(geopandas_obj, pd.DataFrame):
        return infer_geodataframe_schema(geopandas_obj)
    elif isinstance(geopandas_obj, pd.Series):
        return infer_series_schema(geopandas_obj)
    else:
        raise TypeError(
            "geopandas_obj type not recognized. Expected a geopandas "
            f"GeoDataFrame or GeoSeries, found {type(geopandas_obj)}"
        )


def infer_geodataframe_schema(gdf: gpd.GeoDataFrame) -> GeoDataFrameSchema:
    """Infer a GeoDataFrameSchema from a geopandas GeoDataFrame.

    :param gdf: GeoDataFrame object to infer.
    :returns: GeoDataFrameSchema
    """
    pandas_schema = infer_dataframe_schema(gdf)
    schema = GeoDataFrameSchema(
        columns=pandas_schema.columns,
        index=pandas_schema.index,
        coerce=True,
    )

    # enrich geometry columns with the CRS carried by the data, so the
    # inferred schema enforces (and re-applies on coercion) the same CRS
    for col_name, column in schema.columns.items():
        if not isinstance(column.dtype, Geometry):
            continue
        crs = getattr(gdf.get(col_name), "crs", None)
        if crs is not None:
            column.dtype = Geometry(crs=crs)

    schema._is_inferred = True
    return schema

